import{c as t,Q as o,j as a,m as n}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"Account","description":"","frontmatter":{},"headers":[],"relativePath":"guide/portal/account.md","filePath":"guide/portal/account.md","lastUpdated":1778912818000}'),r={name:"guide/portal/account.md"};function s(i,e,l,c,u,h){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="account" tabindex="-1">Account <a class="header-anchor" href="#account" aria-label="Permalink to &quot;Account&quot;">​</a></h1><p>The <strong>Account</strong> page in the Customer Portal manages <strong>your own identity</strong> — your profile, password, MFA devices, and personal preferences. It is separate from the <a href="./settings">Settings</a> page, which configures the customer organisation overall.</p><p>The Account page is the same one available across the Exto platform — see <a href="./../account/managing-your-account">Managing Your Account</a> for the full reference.</p><h2 id="at-a-glance" tabindex="-1">At a glance <a class="header-anchor" href="#at-a-glance" aria-label="Permalink to &quot;At a glance&quot;">​</a></h2><p>The page is split into a left column (editable sections) and a right column (an audit-style log of recent changes to your account).</p><h3 id="left-column" tabindex="-1">Left column <a class="header-anchor" href="#left-column" aria-label="Permalink to &quot;Left column&quot;">​</a></h3><ol><li><strong>Profile</strong> — username (read-only), first / last / nickname / display name; email and phone with verification status.</li><li><strong>User Attributes</strong> — your custom profile fields (visible only if your customer has enabled them). If you belong to multiple customer organisations, an organisation switcher lets you complete attributes for each one.</li><li><strong>Password</strong> — request a password-reset email.</li><li><strong>Multi-Factor Authentication</strong> — enrol authenticator apps, email OTP, and passkeys; remove existing methods.</li><li><strong>Tenant Access</strong> — read-only list of the tenants you can use, with the role you hold in each.</li><li><strong>Identity Provider Links</strong> — read-only list of external accounts linked to your Console identity.</li></ol><h3 id="right-column" tabindex="-1">Right column <a class="header-anchor" href="#right-column" aria-label="Permalink to &quot;Right column&quot;">​</a></h3><p><strong>Account Changes</strong> — a reverse-chronological log of every change to your account. Useful for spotting unauthorised modifications.</p><h2 id="common-tasks" tabindex="-1">Common tasks <a class="header-anchor" href="#common-tasks" aria-label="Permalink to &quot;Common tasks&quot;">​</a></h2><ul><li><strong>Reset my password</strong> — Profile section → <strong>Send Password Reset Email</strong>. A reset link is emailed to you. There is a one-minute cooldown before you can request another.</li><li><strong>Enrol in MFA</strong> — Multi-Factor Authentication section. See <a href="./../account/multi-factor-authentication">Multi-Factor Authentication</a> for the step-by-step.</li><li><strong>Update my display name</strong> — Profile → <strong>Edit Profile</strong> → change → <strong>Save</strong>.</li><li><strong>Verify my phone number</strong> — Profile → Contact Information → enter the number and click <strong>Verify</strong>. A verification SMS arrives; enter the code to confirm.</li><li><strong>Check what changed on my account</strong> — right column. Hover for full details on each entry.</li></ul><h2 id="multi-customer-users" tabindex="-1">Multi-customer users <a class="header-anchor" href="#multi-customer-users" aria-label="Permalink to &quot;Multi-customer users&quot;">​</a></h2><p>If your sign-in is connected to several customer organisations, the User Attributes section shows a switcher across the top. Pick the organisation, fill in its attribute set, and save. Repeat for each.</p><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p>Everyone has access to their own Account page — there is no role gate.</p>',15)])])}const d=t(r,[["render",s]]);export{g as __pageData,d as default};
